+type Clause = { patterns?: any[]; predicate?: (value: any) => unknown; handler: (selection: any, value: any) => any };
+type Entry = Clause | { tap: (result: any) => void };
+
+/** Creates a matcher that evaluates every clause which matches its input. */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): any {
+  return new MatchEachExpression(arguments.length > 0, value, []);
+}
+
+class MatchEachExpression {
+  constructor(private readonly hasInput: boolean, private readonly input: unknown, private readonly entries: Entry[]) {}
+
+  with(...args: any[]) {
+    const handler = args[args.length - 1];
+    let patterns = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns = args.slice(0, -1);
+    return this.add({ patterns, predicate, handler });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return this.add({ predicate, handler });
+  }
+
+  tap(tap: (result: unknown) => void) { return this.add({ tap }); }
+  returnType() { return this; }
+  narrow() { return this; }
+
+  otherwise(handler: (value: unknown) => unknown) {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(fallback = defaultCatcher) {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [fallback(this.input)];
+  }
+
+  run() { return this.exhaustive(); }
+  toFunction() { return (input: unknown) => this.require(input); }
+  toExhaustiveFunction() { return (input: unknown) => this.require(input); }
+  toPartialFunction() { return (input: unknown) => { const results = this.evaluate(input); return results.length ? results : undefined; }; }
